import { notFound } from 'next/navigation'
import { posts } from '../../../data/blog'
import { buildMetadata } from '../../../components/PageSeo'

export function generateMetadata({ params }: { params: { slug: string } }) {
  const post = posts.find((p) => p.slug === params.slug)
  if (!post) return { title: 'Not found' }
  return buildMetadata({
    title: `${post.title} - ToolHub India`,
    description: post.description,
    url: process.env.NEXT_PUBLIC_SITE_URL ? `${process.env.NEXT_PUBLIC_SITE_URL}/blog/${post.slug}` : `/blog/${post.slug}`,
  })
}

export default function Post({ params }: { params: { slug: string } }) {
  const post = posts.find((p) => p.slug === params.slug)
  if (!post) return notFound()

  return (
    <main className="container mx-auto p-4">
      <h1 className="text-2xl font-bold">{post.title}</h1>
      <div className="mt-4 space-y-4 text-slate-700 dark:text-slate-300">
        <p>{post.description}</p>
        <p>{post.content}</p>
      </div>
    </main>
  )
}
